#[derive(Clone)]
struct SessionSlotOptions {
    refresh_worktree: bool,
    prepared_worktree_only: bool,
    replace_active_session: bool,
    terminal_launch_epoch: Option<String>,
    enforcement_mode: Option<String>,
}

impl Default for SessionSlotOptions {
    fn default() -> Self {
        Self {
            refresh_worktree: true,
            prepared_worktree_only: false,
            replace_active_session: false,
            terminal_launch_epoch: None,
            enforcement_mode: None,
        }
    }
}

#[derive(Debug, Clone)]
struct TaskHistoryInterval {
    task_id: String,
    title: String,
    status: String,
    agent_id: Option<String>,
    session_id: Option<String>,
    assigned_role: Option<String>,
    started_at: String,
    finished_at: Option<String>,
    history_started_at: Option<String>,
    history_finished_at: Option<String>,
}

impl TaskHistoryInterval {
    fn effective_finished_at<'a>(&'a self, observed_at: &'a str) -> &'a str {
        self.finished_at
            .as_deref()
            .filter(|value| !value.trim().is_empty())
            .unwrap_or(observed_at)
    }
}

pub fn now_rfc3339() -> String {
    let duration = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_else(|_| Duration::from_secs(0));

    format!("{}.{:03}Z", duration.as_secs(), duration.subsec_millis())
}

fn now_epoch_millis() -> u64 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_else(|_| Duration::from_secs(0))
        .as_millis() as u64
}

fn compact_terminal_todo_plan_text(value: &str, max_chars: usize) -> String {
    let text = value
        .split_whitespace()
        .collect::<Vec<_>>()
        .join(" ")
        .trim()
        .to_string();
    text.chars().take(max_chars).collect()
}

fn normalize_terminal_todo_plan_status(status: &str) -> String {
    match status.trim().to_ascii_lowercase().as_str() {
        "done" | "complete" | "completed" | "finished" | "success" => "completed".to_string(),
        "interrupt" | "interrupted" | "cancelled" | "canceled" | "stopped" => {
            "interrupted".to_string()
        }
        "blocked" => "blocked".to_string(),
        "listed" | "list" | "queued" | "pending" | "ready" => "listed".to_string(),
        "active" | "running" | "in_progress" | "in-progress" | "working" | "" => {
            "active".to_string()
        }
        _ => "active".to_string(),
    }
}

fn normalize_terminal_todo_plan_step_status(status: &str) -> String {
    match status.trim().to_ascii_lowercase().as_str() {
        "done" | "complete" | "completed" | "finished" | "success" => "completed".to_string(),
        "active" | "running" | "current" | "in_progress" | "in-progress" | "working" => {
            "in_progress".to_string()
        }
        "blocked" => "blocked".to_string(),
        "skip" | "skipped" => "skipped".to_string(),
        "queued" | "pending" | "not_started" | "not-started" | "todo" | "" => "queued".to_string(),
        _ => "queued".to_string(),
    }
}

fn terminal_todo_plan_step_user_editable(status: &str) -> bool {
    matches!(
        normalize_terminal_todo_plan_step_status(status).as_str(),
        "queued" | "blocked"
    )
}

fn terminal_todo_plan_is_terminal_status(status: &str) -> bool {
    matches!(
        normalize_terminal_todo_plan_status(status).as_str(),
        "completed" | "interrupted"
    )
}

fn terminal_todo_plan_can_resume(status: &str) -> bool {
    normalize_terminal_todo_plan_status(status) != "completed"
}

fn terminal_todo_plan_step_title_from_value(value: &Value) -> Option<String> {
    value
        .as_str()
        .map(str::to_string)
        .or_else(|| {
            value
                .as_object()
                .and_then(|object| {
                    ["title", "name", "summary", "step"]
                        .iter()
                        .find_map(|key| object.get(*key).and_then(Value::as_str))
                })
                .map(str::to_string)
        })
        .map(|value| {
            compact_terminal_todo_plan_text(&value, TERMINAL_TODO_PLAN_STEP_TITLE_MAX_CHARS)
        })
        .filter(|value| !value.is_empty())
}

fn terminal_todo_plan_step_detail_from_value(value: &Value) -> Option<String> {
    value
        .as_object()
        .and_then(|object| {
            [
                "detail",
                "details",
                "description",
                "current_step_detail",
                "currentStepDetail",
            ]
            .iter()
            .find_map(|key| object.get(*key).and_then(Value::as_str))
        })
        .map(|value| compact_terminal_todo_plan_text(value, 2000))
        .filter(|value| !value.is_empty())
}

#[derive(Clone, Debug)]
struct TerminalTodoPlanStepUpdate {
    step_index: i64,
    title: Option<String>,
    detail: Option<String>,
    status: Option<String>,
}

fn terminal_todo_plan_step_update_values(input: &Value) -> Vec<&Value> {
    [
        "step_updates",
        "stepUpdates",
        "plan_step_updates",
        "planStepUpdates",
        "plan_steps",
        "planSteps",
        "steps",
    ]
    .iter()
    .find_map(|key| input.get(*key).and_then(Value::as_array))
    .map(|values| values.iter().collect())
    .unwrap_or_default()
}

fn terminal_todo_plan_step_index_from_value(value: &Value, fallback: i64) -> i64 {
    optional_i64_field(
        value,
        &[
            "step_index",
            "stepIndex",
            "plan_step_index",
            "planStepIndex",
            "index",
        ],
    )
    .or_else(|| {
        optional_i64_field(value, &["ordinal", "stepOrdinal"])
            .map(|ordinal| ordinal.saturating_sub(1))
    })
    .unwrap_or(fallback)
}

fn terminal_todo_plan_step_updates_from_input(
    input: &Value,
    max_index: i64,
) -> Vec<TerminalTodoPlanStepUpdate> {
    terminal_todo_plan_step_update_values(input)
        .into_iter()
        .enumerate()
        .filter_map(|(position, value)| {
            let step_index = terminal_todo_plan_step_index_from_value(value, position as i64)
                .max(0)
                .min(max_index);
            let title = terminal_todo_plan_step_title_from_value(value);
            let detail = terminal_todo_plan_step_detail_from_value(value);
            let status = string_from_value_keys(
                value,
                &[
                    "status",
                    "step_status",
                    "stepStatus",
                    "plan_step_status",
                    "planStepStatus",
                ],
            )
            .map(|value| normalize_terminal_todo_plan_step_status(&value));
            (title.is_some() || detail.is_some() || status.is_some()).then_some(
                TerminalTodoPlanStepUpdate {
                    step_index,
                    title,
                    detail,
                    status,
                },
            )
        })
        .collect()
}

fn terminal_todo_plan_step_updates_payload(updates: &[TerminalTodoPlanStepUpdate]) -> Value {
    Value::Array(
        updates
            .iter()
            .map(|update| {
                json!({
                    "step_index": update.step_index,
                    "title": update.title,
                    "detail": update.detail,
                    "status": update.status,
                })
            })
            .collect(),
    )
}

fn string_from_value_keys(value: &Value, keys: &[&str]) -> Option<String> {
    keys.iter()
        .find_map(|key| value.get(*key).and_then(Value::as_str))
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string)
}

fn optional_i64_field(value: &Value, keys: &[&str]) -> Option<i64> {
    keys.iter().find_map(|key| {
        value.get(*key).and_then(|candidate| {
            candidate.as_i64().or_else(|| {
                candidate
                    .as_str()
                    .and_then(|text| text.trim().parse::<i64>().ok())
            })
        })
    })
}

fn epoch_millis_from_now_text(value: &str) -> Option<u64> {
    let trimmed = value.trim().strip_suffix('Z').unwrap_or(value.trim());
    let (seconds, millis) = trimmed
        .split_once('.')
        .map(|(seconds, millis)| (seconds, millis))
        .unwrap_or((trimmed, "0"));
    let seconds = seconds.parse::<u64>().ok()?;
    let millis = millis
        .chars()
        .take(3)
        .collect::<String>()
        .parse::<u64>()
        .unwrap_or(0);
    Some(seconds.saturating_mul(1000).saturating_add(millis))
}

fn uuid() -> String {
    Uuid::new_v4().to_string()
}

fn bool_i64(value: bool) -> i64 {
    if value {
        1
    } else {
        0
    }
}

pub(crate) const AGENT_SESSION_MODE_WORKTREE_COORDINATION: &str = "worktree_coordination";
pub(crate) const AGENT_SESSION_MODE_DIRECT_COORDINATION: &str = "direct_coordination";
pub(crate) const AGENT_SESSION_MODE_DIRECT_UNMANAGED: &str = "direct_unmanaged";

pub(crate) fn normalize_agent_session_mode(value: &str) -> Option<&'static str> {
    match value.trim().to_ascii_lowercase().as_str() {
        "worktree_coordination" | "isolated" | "safe" => {
            Some(AGENT_SESSION_MODE_WORKTREE_COORDINATION)
        }
        "direct_coordination" | "coordinated" => Some(AGENT_SESSION_MODE_DIRECT_COORDINATION),
        "direct_unmanaged" | "direct" | "unmanaged" => Some(AGENT_SESSION_MODE_DIRECT_UNMANAGED),
        _ => None,
    }
}

pub(crate) fn repo_policy_agent_session_mode(policy: &Value) -> &'static str {
    policy["agent_session_mode"]
        .as_str()
        .and_then(normalize_agent_session_mode)
        .unwrap_or_else(|| {
            if policy["agent_worktree_required"].as_i64().unwrap_or(0) == 1 {
                AGENT_SESSION_MODE_WORKTREE_COORDINATION
            } else {
                AGENT_SESSION_MODE_DIRECT_COORDINATION
            }
        })
}

fn repo_policy_requires_agent_worktree(policy: &Value) -> bool {
    repo_policy_agent_session_mode(policy) == AGENT_SESSION_MODE_WORKTREE_COORDINATION
}

fn write_enforcement_safety_rank(mode: &str) -> Option<u8> {
    match mode {
        "worktree_required" => Some(3),
        "bounded_direct_edit" => Some(2),
        "direct_unmanaged" => Some(1),
        _ => None,
    }
}

fn required_trimmed<'a>(value: &'a str, key: &str) -> Result<&'a str, String> {
    let trimmed = value.trim();
    if trimmed.is_empty() {
        Err(format!("{key} is required."))
    } else {
        Ok(trimmed)
    }
}

fn required_json_text<'a>(input: &'a Value, key: &str) -> Result<&'a str, String> {
    input[key]
        .as_str()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .ok_or_else(|| format!("{key} is required."))
}

fn workspace_mcp_secret_key(value: &str) -> Result<String, String> {
    let key = required_trimmed(value, "key")?.to_ascii_uppercase();
    let mut chars = key.chars();
    let Some(first) = chars.next() else {
        return Err("key is required.".to_string());
    };
    if !(first.is_ascii_alphabetic() || first == '_')
        || !chars.all(|character| character.is_ascii_alphanumeric() || character == '_')
    {
        return Err(
            "Secret keys must be env-style names using letters, numbers, and underscores."
                .to_string(),
        );
    }
    Ok(key)
}

fn workspace_mcp_secret_public_row(mut row: Value) -> Value {
    row["available"] = json!(row["available"].as_i64().unwrap_or_default() != 0);
    row
}

fn json_text_or_default(value: Option<&Value>, default: Value) -> Result<String, String> {
    match value {
        Some(value) if !value.is_null() => serde_json::to_string(value),
        _ => serde_json::to_string(&default),
    }
    .map_err(|error| format!("Unable to serialize workspace MCP JSON: {error}"))
}

fn workspace_mcp_key(value: &str) -> String {
    let mut out = String::new();
    let mut previous_dash = false;
    for ch in value.trim().chars() {
        let next = if ch.is_ascii_alphanumeric() {
            previous_dash = false;
            Some(ch.to_ascii_lowercase())
        } else if matches!(ch, '-' | '_' | '.') {
            previous_dash = ch == '-';
            Some(ch)
        } else if ch.is_whitespace() || matches!(ch, '/' | ':' | '@') {
            if previous_dash || out.is_empty() {
                None
            } else {
                previous_dash = true;
                Some('-')
            }
        } else {
            None
        };
        if let Some(next) = next {
            out.push(next);
        }
    }
    while out.ends_with('-') {
        out.pop();
    }
    if out.is_empty() {
        "mcp-server".to_string()
    } else {
        out
    }
}

fn workspace_mcp_approval_policy(value: Option<&str>) -> &'static str {
    match value
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or(WORKSPACE_MCP_APPROVAL_ALWAYS_ALLOW)
        .to_ascii_lowercase()
        .as_str()
    {
        "prompt" | "ask" | "manual" | "confirm" => WORKSPACE_MCP_APPROVAL_PROMPT,
        _ => WORKSPACE_MCP_APPROVAL_ALWAYS_ALLOW,
    }
}

fn workspace_mcp_exposure_mode(value: Option<&str>) -> &'static str {
    match value
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or(WORKSPACE_MCP_EXPOSURE_LAZY)
        .to_ascii_lowercase()
        .as_str()
    {
        "pinned" | "direct" | "direct_tools" | "direct-tools" => WORKSPACE_MCP_EXPOSURE_PINNED,
        "hidden" | "none" | "off" => WORKSPACE_MCP_EXPOSURE_HIDDEN,
        _ => WORKSPACE_MCP_EXPOSURE_LAZY,
    }
}

fn config_value_present(config_values: &Value, key: &str) -> bool {
    let Some(value) = config_values.get(key) else {
        return false;
    };
    if let Some(text) = value.as_str() {
        return !text.trim().is_empty();
    }
    if let Some(object) = value.as_object() {
        return object
            .get("value")
            .and_then(Value::as_str)
            .is_some_and(|value| !value.trim().is_empty());
    }
    !value.is_null()
}

fn missing_required_config(env_schema: &Value, config_values: &Value) -> Vec<Value> {
    env_schema
        .as_array()
        .into_iter()
        .flatten()
        .filter(|entry| entry["required"].as_bool() == Some(true))
        .filter_map(|entry| {
            let key = entry["key"].as_str()?.trim();
            if key.is_empty() || config_value_present(config_values, key) {
                None
            } else {
                Some(json!({
                    "key": key,
                    "label": entry["label"].as_str().unwrap_or(key),
                    "secret": entry["secret"].as_bool().unwrap_or(false),
                }))
            }
        })
        .collect::<Vec<_>>()
}

fn mcp_badge_state(status: &str) -> &'static str {
    match status {
        "healthy" | "enabled" | "installed" | "seeing_mcp" | "confirmed" | "configured" => {
            "enabled"
        }
        "failed" | "auth_required" | "config_required" | "error" | "not_connected"
        | "spawn_failed" | "handshake_failed" | "timeout" | "missing_command" | "write_failed"
        | "read_failed" | "wait_failed" | "invalid_response" => "blocked",
        _ => "planned",
    }
}

fn workspace_mcp_connected_status(status: &str) -> bool {
    matches!(status, "healthy" | "connected" | "responded")
}

fn workspace_mcp_connection_message(
    row: &Value,
    status: &str,
    workspace_enabled: bool,
    configured: bool,
    install_state: &str,
) -> String {
    let last_probe_message = row["last_probe_message"]
        .as_str()
        .map(str::trim)
        .filter(|value| !value.is_empty());
    if install_state != "installed" {
        return format!("Install state is `{install_state}`.");
    }
    if matches!(status, "installing" | "checking" | "queued") {
        return last_probe_message
            .unwrap_or("Workspace MCP connection work is still running.")
            .to_string();
    }
    if matches!(status, "spawn_failed" | "failed") {
        return last_probe_message
            .unwrap_or("Workspace MCP connection failed.")
            .to_string();
    }
    if !workspace_enabled {
        return "This MCP is installed but disabled for this workspace.".to_string();
    }
    if !configured {
        return "Required workspace configuration is missing.".to_string();
    }
    if workspace_mcp_connected_status(status) {
        return last_probe_message
            .unwrap_or("The workspace gateway successfully listed this MCP's tools.")
            .to_string();
    }
    last_probe_message
        .unwrap_or(
            "This MCP is enabled and configured, but the workspace gateway has not connected yet.",
        )
        .to_string()
}

fn workspace_mcp_visibility(
    enabled: bool,
    configured: bool,
    client_mount_summary: &Value,
    built_in: bool,
) -> Vec<Value> {
    client_mount_summary["mounts"]
        .as_array()
        .into_iter()
        .flatten()
        .map(|mount| {
            let base_status = mount["status"].as_str().unwrap_or("not_seen");
            let status = if built_in {
                base_status.to_string()
            } else if !enabled {
                "workspace_disabled".to_string()
            } else if !configured {
                "config_required".to_string()
            } else {
                "gateway_pending".to_string()
            };
            let message = if built_in {
                "Coordination Kernel mount reported by the active agent.".to_string()
            } else if !enabled {
                "This MCP is installed but disabled for the workspace.".to_string()
            } else if !configured {
                "Required workspace configuration is missing.".to_string()
            } else {
                "Exposed through the workspace MCP gateway when the agent refreshes its MCP tools."
                    .to_string()
            };
            json!({
                "session_id": mount["session_id"].clone(),
                "agent_kind": mount["agent_kind"].clone(),
                "agent_name": mount["agent_name"].clone(),
                "slot_key": mount["slot_key"].clone(),
                "status": status,
                "badge_state": mcp_badge_state(&status),
                "message": message,
                "last_seen_event": mount["last_event_type"].clone(),
                "last_seen_at": mount["last_event_at"].clone(),
            })
        })
        .collect::<Vec<_>>()
}

fn coordination_workspace_mcp_server(status: &Value) -> Value {
    let health = &status["health"];
    let client_mount_summary = &health["agent_client_mount_summary"];
    let status_text = health["status"].as_str().unwrap_or("warning");
    json!({
        "id": "coordination-kernel",
        "server_key": "coordination-kernel",
        "name": "Coordination Kernel",
        "description": "Built-in task coordination, leases, checkpoints, and patch submission.",
        "built_in": true,
        "toggleable": false,
        "source_kind": "built_in",
        "source_label": "Diff Forge",
        "package_ref": "internal",
        "version": "",
        "transport": "stdio",
        "command": status["command"].clone(),
        "args_json": status["args"].clone(),
        "url": Value::Null,
        "env_schema_json": [],
        "config_values_json": {},
        "missing_required_config": [],
        "tools_json": crate::coordination::mcp::TOOL_NAMES,
        "install_state": "installed",
        "workspace_enabled": true,
        "approval_policy": WORKSPACE_MCP_APPROVAL_ALWAYS_ALLOW,
        "exposure_mode": WORKSPACE_MCP_EXPOSURE_PINNED,
        "agent_config_access_enabled": true,
        "agent_secret_config_access_enabled": false,
        "agent_env_file_write_enabled": true,
        "status": status_text,
        "badge_state": mcp_badge_state(status_text),
        "config_status": "configured",
        "last_probe_status": health["spawn_probe"]["status"].clone(),
        "last_probe_message": health["spawn_probe"]["error"].clone(),
        "agent_visibility": workspace_mcp_visibility(true, true, client_mount_summary, true),
        "runtime_note": "Always mounted as a required Diff Forge coordination server.",
    })
}

