    fn fake_cloud_mcp_url(default_task_id: &str, omit_task_id: bool) -> String {
        let listener = std::net::TcpListener::bind("127.0.0.1:0").unwrap();
        let url = format!("http://{}", listener.local_addr().unwrap());
        let default_task_id = default_task_id.to_string();
        thread::spawn(move || {
            for stream in listener.incoming().flatten().take(32) {
                handle_fake_cloud_mcp_stream(stream, default_task_id.clone(), omit_task_id);
            }
        });
        url
    }

    fn handle_fake_cloud_mcp_stream(
        mut stream: std::net::TcpStream,
        default_task_id: String,
        omit_task_id: bool,
    ) {
        use std::io::{Read, Write};

        let _ = stream.set_read_timeout(Some(std::time::Duration::from_millis(500)));
        let mut buffer = Vec::new();
        let mut chunk = [0u8; 4096];
        while let Ok(read) = stream.read(&mut chunk) {
            if read == 0 {
                break;
            }
            buffer.extend_from_slice(&chunk[..read]);
            if buffer.windows(4).any(|window| window == b"\r\n\r\n") {
                break;
            }
        }
        let request_text = String::from_utf8_lossy(&buffer);
        let header_text = request_text
            .split_once("\r\n\r\n")
            .map(|(headers, _)| headers)
            .unwrap_or(request_text.as_ref());
        if header_text
            .lines()
            .any(|line| line.to_ascii_lowercase().starts_with("upgrade: websocket"))
        {
            let websocket_key = header_text
                .lines()
                .find_map(|line| {
                    let (name, value) = line.split_once(':')?;
                    name.eq_ignore_ascii_case("sec-websocket-key")
                        .then(|| value.trim().to_string())
                })
                .unwrap_or_default();
            let accept_key = fake_websocket_accept_key(&websocket_key);
            let response = format!(
                "HTTP/1.1 101 Switching Protocols\r\nUpgrade: websocket\r\nConnection: Upgrade\r\nSec-WebSocket-Accept: {}\r\n\r\n",
                accept_key
            );
            let _ = stream.write_all(response.as_bytes());
            let _ = fake_write_ws_text(
                &mut stream,
                &json!({
                    "kind": "cloud_app_ws_ready",
                    "connection_id": "fake-cloud-connection",
                    "message_auth": {"message_token": "fake-message-token"}
                })
                .to_string(),
            );
            if let Ok(envelope_text) = fake_read_ws_text(&mut stream) {
                let envelope = serde_json::from_str::<serde_json::Value>(&envelope_text)
                    .unwrap_or_else(|_| json!({}));
                let request_json = envelope
                    .get("request")
                    .cloned()
                    .unwrap_or_else(|| json!({}));
                let data = fake_cloud_response_data(
                    envelope["kind"].as_str().unwrap_or("event"),
                    &request_json,
                    default_task_id.as_str(),
                    omit_task_id,
                );
                let reply = json!({
                    "id": envelope["id"].clone(),
                    "ok": true,
                    "data": data,
                });
                let _ = fake_write_ws_text(&mut stream, &reply.to_string());
            }
            return;
        }
        let content_length = header_text
            .lines()
            .find_map(|line| {
                let (name, value) = line.split_once(':')?;
                name.eq_ignore_ascii_case("content-length")
                    .then(|| value.trim().parse::<usize>().ok())
                    .flatten()
            })
            .unwrap_or(0);
        let header_end = buffer
            .windows(4)
            .position(|window| window == b"\r\n\r\n")
            .map(|index| index + 4)
            .unwrap_or(buffer.len());
        while buffer.len().saturating_sub(header_end) < content_length {
            match stream.read(&mut chunk) {
                Ok(0) => break,
                Ok(read) => buffer.extend_from_slice(&chunk[..read]),
                Err(_) => break,
            }
        }
        let request_text = String::from_utf8_lossy(&buffer);
        let path = request_text
            .lines()
            .next()
            .and_then(|line| line.split_whitespace().nth(1))
            .unwrap_or("/");
        let body_text = request_text
            .split_once("\r\n\r\n")
            .map(|(_, body)| body)
            .unwrap_or_default();
        let request_json =
            serde_json::from_str::<serde_json::Value>(body_text).unwrap_or_else(|_| json!({}));
        let body = if path == "/v1/events" {
            json!({"data": fake_cloud_response_data("event", &request_json, default_task_id.as_str(), omit_task_id)})
        } else if path == "/v1/task/history" {
            json!({"data": fake_cloud_response_data("task_history", &request_json, default_task_id.as_str(), omit_task_id)})
        } else {
            json!({"data": {"ok": true}})
        }
        .to_string();
        let response = format!(
            "HTTP/1.1 200 OK\r\nContent-Type: application/json\r\nContent-Length: {}\r\nConnection: close\r\n\r\n{}",
            body.len(),
            body
        );
        let _ = stream.write_all(response.as_bytes());
    }

    fn fake_cloud_response_data(
        kind: &str,
        request_json: &serde_json::Value,
        default_task_id: &str,
        omit_task_id: bool,
    ) -> serde_json::Value {
        if kind == "event" {
            let requested_task_id = request_json["payload"]["task_id"]
                .as_str()
                .filter(|value| !value.trim().is_empty())
                .unwrap_or(default_task_id);
            if omit_task_id {
                json!({
                    "task": {},
                    "spec_activity": {"recorded": true, "node_ids": ["spec-test"]}
                })
            } else {
                json!({
                    "task_id": requested_task_id,
                    "task": {"id": requested_task_id},
                    "spec_activity": {"recorded": true, "node_ids": ["spec-test"]}
                })
            }
        } else if kind == "task_history" {
            json!({
                "kind": "task_history",
                "version": 1,
                "repo_id": "repo-test",
                "workspace_id": "workspace-test",
                "tasks": []
            })
        } else {
            json!({"ok": true})
        }
    }

    fn fake_websocket_accept_key(key: &str) -> String {
        use base64::{engine::general_purpose, Engine as _};
        use sha1::{Digest as _, Sha1};

        let mut hasher = Sha1::new();
        hasher.update(key.as_bytes());
        hasher.update(b"258EAFA5-E914-47DA-95CA-C5AB0DC85B11");
        general_purpose::STANDARD.encode(hasher.finalize())
    }

    fn fake_write_ws_text(stream: &mut std::net::TcpStream, text: &str) -> std::io::Result<()> {
        let payload = text.as_bytes();
        let mut frame = Vec::with_capacity(payload.len() + 10);
        frame.push(0x81);
        if payload.len() <= 125 {
            frame.push(payload.len() as u8);
        } else if payload.len() <= u16::MAX as usize {
            frame.push(126);
            frame.extend_from_slice(&(payload.len() as u16).to_be_bytes());
        } else {
            frame.push(127);
            frame.extend_from_slice(&(payload.len() as u64).to_be_bytes());
        }
        frame.extend_from_slice(payload);
        stream.write_all(&frame)
    }

    fn fake_read_ws_text(stream: &mut std::net::TcpStream) -> Result<String, String> {
        let mut header = [0u8; 2];
        stream
            .read_exact(&mut header)
            .map_err(|error| error.to_string())?;
        let opcode = header[0] & 0x0F;
        if opcode != 0x1 {
            return Err(format!("unexpected websocket opcode {opcode}"));
        }
        let masked = header[1] & 0x80 != 0;
        let mut length = u64::from(header[1] & 0x7F);
        if length == 126 {
            let mut extended = [0u8; 2];
            stream
                .read_exact(&mut extended)
                .map_err(|error| error.to_string())?;
            length = u64::from(u16::from_be_bytes(extended));
        } else if length == 127 {
            let mut extended = [0u8; 8];
            stream
                .read_exact(&mut extended)
                .map_err(|error| error.to_string())?;
            length = u64::from_be_bytes(extended);
        }
        let mask = if masked {
            let mut mask = [0u8; 4];
            stream
                .read_exact(&mut mask)
                .map_err(|error| error.to_string())?;
            Some(mask)
        } else {
            None
        };
        let mut payload = vec![0u8; length as usize];
        stream
            .read_exact(&mut payload)
            .map_err(|error| error.to_string())?;
        if let Some(mask) = mask {
            for (index, byte) in payload.iter_mut().enumerate() {
                *byte ^= mask[index % 4];
            }
        }
        String::from_utf8(payload).map_err(|error| error.to_string())
    }

    #[test]
    fn atomic_text_writes_use_isolated_temp_files_under_concurrency() {
        let repo = temp_repo("atomic_text_concurrency");
        let path = repo.join("coordination.codex.toml");
        let writers = 16;
        let barrier = Arc::new(Barrier::new(writers));
        let handles = (0..writers)
            .map(|index| {
                let barrier = Arc::clone(&barrier);
                let path = path.clone();
                thread::spawn(move || {
                    barrier.wait();
                    write_text_file_atomic(&path, &format!("writer-{index}\n"))
                })
            })
            .collect::<Vec<_>>();

        for handle in handles {
            handle.join().unwrap().unwrap();
        }

        let final_body = fs::read_to_string(&path).unwrap();
        assert!(final_body.starts_with("writer-"));
        let temp_files = fs::read_dir(&repo)
            .unwrap()
            .filter_map(Result::ok)
            .filter(|entry| {
                entry.path().extension().and_then(|value| value.to_str()) == Some("tmp")
            })
            .count();
        assert_eq!(temp_files, 0);
    }

