    #[test]
    fn native_plan_update_records_reuses_and_resets_session_plans() {
        let repo = init_git_repo("native_plan_capture");
        let kernel = CoordinationKernel::init(&repo, None).unwrap();

        let first = kernel
            .record_terminal_todo_plan_from_native_update(
                "session-native",
                Some("codex"),
                Some("workspace-test"),
                &json!({
                    "tool": "todowrite",
                    "steps": [
                        {"title": "Find the bug", "status": "completed"},
                        {"title": "Fix the bug", "status": "in_progress"},
                        {"title": "Run tests", "status": "pending"}
                    ]
                }),
            )
            .unwrap()
            .unwrap();
        let plan_id = first["plan"]["plan_id"].as_str().unwrap().to_string();
        assert!(plan_id.starts_with("native-"));
        assert_eq!(first["plan"]["status"].as_str(), Some("active"));
        assert_eq!(first["plan"]["current_step_index"].as_i64(), Some(1));
        assert_eq!(first["plan"]["steps"].as_array().map(Vec::len), Some(3));

        // Same-session rewrite with overlapping titles updates the same plan.
        let second = kernel
            .record_terminal_todo_plan_from_native_update(
                "session-native",
                Some("codex"),
                Some("workspace-test"),
                &json!({
                    "tool": "todowrite",
                    "steps": [
                        {"title": "Find the bug", "status": "completed"},
                        {"title": "Fix the bug", "status": "completed"},
                        {"title": "Run tests", "status": "completed"}
                    ]
                }),
            )
            .unwrap()
            .unwrap();
        assert_eq!(second["plan"]["plan_id"].as_str(), Some(plan_id.as_str()));
        assert_eq!(second["plan"]["status"].as_str(), Some("completed"));

        // A disjoint list after completion starts a fresh plan (list reset).
        let third = kernel
            .record_terminal_todo_plan_from_native_update(
                "session-native",
                Some("codex"),
                Some("workspace-test"),
                &json!({
                    "tool": "update_plan",
                    "explanation": "Ship the docs",
                    "steps": [
                        {"title": "Write release notes", "status": "in_progress"},
                        {"title": "Publish docs", "status": "pending"}
                    ]
                }),
            )
            .unwrap()
            .unwrap();
        let third_plan_id = third["plan"]["plan_id"].as_str().unwrap();
        assert_ne!(third_plan_id, plan_id.as_str());
        assert_eq!(third["plan"]["title"].as_str(), Some("Ship the docs"));

        // Session-targeted snapshot resolves the newest native plan.
        let snapshot = kernel
            .terminal_todo_plan_snapshot(None, Some("session-native"), None, None)
            .unwrap();
        assert_eq!(
            snapshot["data"]["selected_plan"]["plan_id"].as_str(),
            Some(third_plan_id)
        );
        assert_eq!(
            snapshot["data"]["selected_plan"]["steps"]
                .as_array()
                .map(Vec::len),
            Some(2)
        );
    }

    #[test]
    fn update_plan_ticks_steps_without_task_id() {
        let repo = init_git_repo("taskless_terminal_todo_plan_update");
        let kernel = CoordinationKernel::init(&repo, None).unwrap();
        let created = json!({
            "plan_id": "local-plan-update",
            "todo_id": "local-plan-update-todo-1",
            "compact_plan": {
                "plan_id": "local-plan-update",
                "todo_id": "local-plan-update-todo-1",
                "title": "Taskless plan ticking",
                "status": "listed",
                "current_step_index": 0,
                "steps": [
                    {
                        "id": "local-plan-update-todo-1",
                        "todo_id": "local-plan-update-todo-1",
                        "index": 0,
                        "title": "First step",
                        "status": "listed"
                    },
                    {
                        "id": "local-plan-update-todo-2",
                        "todo_id": "local-plan-update-todo-2",
                        "index": 1,
                        "title": "Second step",
                        "status": "listed"
                    }
                ]
            }
        });
        kernel
            .record_terminal_todo_plan_from_create_plan(
                &created,
                &json!({
                    "workspace_id": "workspace-test",
                    "agent_id": "codex",
                    "session_id": "session-test"
                }),
            )
            .unwrap()
            .unwrap();

        let updated = kernel
            .update_terminal_todo_plan(
                Some("codex"),
                Some("session-test"),
                &json!({
                    "plan_id": "local-plan-update",
                    "completed_step_index": 0,
                    "current_step_detail": "Working on the second step",
                }),
            )
            .unwrap()
            .unwrap();
        let steps = updated["plan"]["steps"].as_array().unwrap();
        assert_eq!(steps[0]["status"].as_str(), Some("completed"));
        assert_eq!(steps[1]["status"].as_str(), Some("in_progress"));
        assert_eq!(updated["plan"]["current_step_index"].as_i64(), Some(1));

        let finished = kernel
            .update_terminal_todo_plan(
                Some("codex"),
                Some("session-test"),
                &json!({
                    "plan_id": "local-plan-update",
                    "completed_step_index": 1,
                    "plan_status": "completed",
                }),
            )
            .unwrap()
            .unwrap();
        assert_eq!(finished["plan"]["status"].as_str(), Some("completed"));
    }

    #[test]
    fn terminal_todo_plan_user_edits_only_unlocked_steps() {
        let repo = init_git_repo("terminal_plan_user_edit_locks");
        let kernel = CoordinationKernel::init(&repo, None).unwrap();
        let agent = kernel.create_or_get_agent("Codex", "codex", None).unwrap();
        let agent_id = agent["id"].as_str().unwrap();
        let task = kernel
            .create_task("Plan task", None, 0, 1, None, None, None, None)
            .unwrap();
        let task_id = task["id"].as_str().unwrap();

        let plan_id = seed_terminal_todo_plan_for_test(
            &kernel,
            task_id,
            Some(agent_id),
            None,
            "Plan task",
            &["Inspect", "Patch", "Verify"],
            0,
        );

        let active_edit = kernel
            .edit_terminal_todo_plan_step_title(&plan_id, 0, "User active edit", Some("user"))
            .unwrap();
        assert_eq!(active_edit["ok"].as_bool(), Some(false));
        assert_eq!(
            active_edit["error"]["code"].as_str(),
            Some("terminal_todo_plan_step_not_editable")
        );

        let queued_edit = kernel
            .edit_terminal_todo_plan_step_title(&plan_id, 1, "User queued edit", Some("user"))
            .unwrap();
        assert_eq!(queued_edit["ok"].as_bool(), Some(true));
        assert_eq!(
            queued_edit["data"]["plan"]["steps"][1]["title"].as_str(),
            Some("User queued edit")
        );

        kernel
            .checkpoint_terminal_todo_plan(
                task_id,
                Some(agent_id),
                None,
                &json!({
                    "current_step_index": 1,
                    "plan_step_status": "blocked"
                }),
            )
            .unwrap()
            .unwrap();
        let blocked_edit = kernel
            .edit_terminal_todo_plan_step_title(&plan_id, 1, "User blocked edit", Some("user"))
            .unwrap();
        assert_eq!(blocked_edit["ok"].as_bool(), Some(true));
        assert_eq!(
            blocked_edit["data"]["plan"]["steps"][1]["title"].as_str(),
            Some("User blocked edit")
        );

        let completed_edit = kernel
            .edit_terminal_todo_plan_step_title(&plan_id, 0, "User completed edit", Some("user"))
            .unwrap();
        assert_eq!(completed_edit["ok"].as_bool(), Some(false));
    }

