    #[test]
    fn terminal_todo_plan_snapshot_uses_terminal_lineage_after_restart() {
        let repo = init_git_repo("terminal_plan_restart_lineage");
        let kernel = CoordinationKernel::init(&repo, None).unwrap();
        let agent = kernel.create_or_get_agent("Codex", "codex", None).unwrap();
        let agent_id = agent["id"].as_str().unwrap();
        let pty_id = "workspace-terminal-test-0-codex";

        let first_session = kernel
            .create_session_for_slot_key(
                "1",
                "Codex 1",
                "codex",
                None,
                None,
                Some(pty_id),
                false,
                None,
                None,
            )
            .unwrap();
        let first_session_id = first_session["id"].as_str().unwrap().to_string();

        let stale_task = kernel
            .create_task("Older unfinished plan", None, 0, 1, None, None, None, None)
            .unwrap();
        let stale_task_id = stale_task["id"].as_str().unwrap();
        let stale_plan_id = seed_terminal_todo_plan_for_test(
            &kernel,
            stale_task_id,
            Some(agent_id),
            Some(&first_session_id),
            "Older unfinished plan",
            &["Draft", "Patch"],
            0,
        );
        kernel
            .conn
            .execute(
                "UPDATE terminal_todo_plans SET updated_at='0000-01-01T00:00:00.000Z' WHERE id=?1",
                params![&stale_plan_id],
            )
            .unwrap();

        let completed_task = kernel
            .create_task("Completed plan", None, 0, 1, None, None, None, None)
            .unwrap();
        let completed_task_id = completed_task["id"].as_str().unwrap();
        let completed_plan_id = seed_terminal_todo_plan_for_test(
            &kernel,
            completed_task_id,
            Some(agent_id),
            Some(&first_session_id),
            "Completed plan",
            &["Inspect", "Patch", "Verify"],
            2,
        );
        kernel
            .finish_terminal_todo_plan(
                &completed_plan_id,
                "completed",
                Some(agent_id),
                Some(&first_session_id),
            )
            .unwrap();

        kernel
            .interrupt_session(&first_session_id, "terminal_restarted")
            .unwrap();
        let restarted_session = kernel
            .create_session_for_slot_key(
                "1",
                "Codex 1",
                "codex",
                None,
                None,
                Some(pty_id),
                false,
                None,
                None,
            )
            .unwrap();
        let restarted_session_id = restarted_session["id"].as_str().unwrap();

        let snapshot = kernel
            .terminal_todo_plan_snapshot(None, Some(restarted_session_id), Some("codex"), None)
            .unwrap();
        assert_eq!(
            snapshot["data"]["history_scope"].as_str(),
            Some("session_lineage")
        );
        assert_eq!(
            snapshot["data"]["selected_plan"]["plan_id"].as_str(),
            Some(completed_plan_id.as_str())
        );
        assert_eq!(
            snapshot["data"]["selected_plan"]["status"].as_str(),
            Some("completed")
        );
    }

    #[test]
    fn storage_and_schema_migration_logging_is_persisted() {
        let repo = temp_repo("storage_logging");
        let kernel = CoordinationKernel::init(&repo, None).unwrap();

        let storage_events = kernel
            .query_json(
                "SELECT * FROM events WHERE event_type='kernel_storage_opened'",
                &[],
            )
            .unwrap();
        assert_eq!(storage_events.len(), 1);
        let payload = &storage_events[0]["payload_json"];
        assert_eq!(payload["wal_enabled"].as_bool(), Some(true));
        assert_eq!(payload["foreign_keys_enabled"].as_bool(), Some(true));
        assert_eq!(payload["busy_timeout_ms"].as_i64(), Some(30_000));
        assert!(
            payload["paths"]["ensured_directory_count"]
                .as_i64()
                .unwrap_or_default()
                > 0
        );
        assert!(payload["migrations"]
            .as_array()
            .unwrap()
            .iter()
            .any(|migration| migration["name"].as_str() == Some("coordination_kernel_initial")));

        let migration_events = kernel
            .query_json(
                "SELECT * FROM events WHERE event_type IN ('schema_migration_applied', 'schema_migration_checked', 'schema_migration_ensured')",
                &[],
            )
            .unwrap();
        assert!(migration_events
            .iter()
            .any(|event| event["payload_json"]["name"].as_str()
                == Some("coordination_kernel_runtime_guards")));

        let migration_rows = kernel
            .query_json("SELECT * FROM schema_migrations ORDER BY version", &[])
            .unwrap();
        assert!(migration_rows
            .iter()
            .any(|row| row["version"].as_i64() == Some(1)));
        assert!(migration_rows
            .iter()
            .any(|row| row["version"].as_i64() == Some(3)));
        assert!(migration_rows
            .iter()
            .any(|row| row["version"].as_i64() == Some(5)));

        if alignment::is_enabled() {
            let log = fs::read_to_string(alignment::log_path(&repo)).unwrap();
            assert!(log.contains("\"event\":\"kernel.initialized\""));
        }
    }

    #[test]
    fn repo_policy_gate_rejects_unsafe_downgrades() {
        let repo = temp_repo("policy_gate");
        let kernel = CoordinationKernel::init(&repo, None).unwrap();

        let enabled_worktrees = kernel
            .update_repo_policy(&json!({"agent_worktree_required": true}))
            .unwrap();
        assert_eq!(
            enabled_worktrees["data"]["agent_worktree_required"].as_i64(),
            Some(1)
        );
        let disabled_worktrees = kernel
            .update_repo_policy(&json!({"agent_worktree_required": false}))
            .unwrap();
        assert_eq!(
            disabled_worktrees["data"]["agent_worktree_required"].as_i64(),
            Some(0)
        );
        assert!(kernel
            .update_repo_policy(&json!({"patch_lease_validation_required": 0}))
            .is_err());
        assert!(kernel
            .update_repo_policy(&json!({"merge_gate_required": false}))
            .is_err());
        assert!(kernel
            .update_repo_policy(&json!({"unleased_write_policy": "warn"}))
            .is_err());
        assert!(kernel
            .update_repo_policy(&json!({"raw_sql_mcp_allowed": true}))
            .is_err());

        let policy = kernel.repo_policy().unwrap();
        assert_eq!(policy["agent_worktree_required"].as_i64(), Some(0));
        assert_eq!(policy["patch_lease_validation_required"].as_i64(), Some(1));
        assert_eq!(policy["merge_gate_required"].as_i64(), Some(1));
        assert_eq!(
            policy["unleased_write_policy"].as_str(),
            Some("reject_patch")
        );
        assert_eq!(policy["raw_sql_mcp_allowed"].as_i64(), Some(0));

        let updated = kernel
            .update_repo_policy(&json!({
                "integrator_enabled": true,
                "integrator_agent_id": "codex",
                "integrator_model": "gpt-5.5",
                "integrator_reasoning_effort": "xhigh",
            }))
            .unwrap();
        assert_eq!(
            updated["data"]["integrator_reasoning_effort"].as_str(),
            Some("xhigh")
        );
        assert!(kernel
            .update_repo_policy(&json!({"integrator_reasoning_effort": "max"}))
            .is_err());
        assert!(kernel
            .update_repo_policy(&json!({"integrator_model": ""}))
            .is_err());
    }

    #[test]
    fn concurrent_task_history_records_integration_batch_members() {
        let repo = init_git_repo("concurrent_batch_members");
        let kernel = CoordinationKernel::init(&repo, None).unwrap();
        enable_agent_worktrees(&kernel);
        kernel
            .update_repo_policy(&json!({"integrator_enabled": true}))
            .unwrap();

        let session_a = kernel
            .create_session_for_slot_key(
                "concurrent-a",
                "Agent A",
                "codex",
                None,
                None,
                None,
                true,
                None,
                None,
            )
            .unwrap();
        let agent_a_id = session_a["agentId"].as_str().unwrap();
        let session_a_id = session_a["id"].as_str().unwrap();
        let worktree_a_id = session_a["worktreeId"].as_str().unwrap();
        let task_a = kernel
            .create_task("Task A", Some("first intent"), 0, 1, None, None, None, None)
            .unwrap();
        let task_a_id = task_a["id"].as_str().unwrap();
        kernel
            .claim_task(task_a_id, agent_a_id, session_a_id)
            .unwrap();

        let session_b = kernel
            .create_session_for_slot_key(
                "concurrent-b",
                "Agent B",
                "codex",
                None,
                None,
                None,
                true,
                None,
                None,
            )
            .unwrap();
        let agent_b_id = session_b["agentId"].as_str().unwrap();
        let session_b_id = session_b["id"].as_str().unwrap();
        let task_b = kernel
            .create_task(
                "Task B",
                Some("second intent"),
                0,
                1,
                None,
                None,
                None,
                None,
            )
            .unwrap();
        let task_b_id = task_b["id"].as_str().unwrap();
        kernel
            .claim_task(task_b_id, agent_b_id, session_b_id)
            .unwrap();

        let patch_id = uuid();
        kernel
            .create_patch_row(
                &patch_id,
                task_a_id,
                agent_a_id,
                session_a_id,
                worktree_a_id,
                Some("HEAD"),
                None,
                None,
                "submitted",
                1,
                None,
                None,
                Some("task a submitted"),
            )
            .unwrap();
        kernel
            .conn
            .execute(
                "INSERT INTO patch_files(
                    id, patch_id, path, change_kind, old_hash, new_hash,
                    lines_added, lines_removed
                 ) VALUES(?1, ?2, 'src.txt', 'modified', NULL, NULL, NULL, NULL)",
                params![uuid(), &patch_id],
            )
            .unwrap();

        let batch = kernel
            .record_concurrent_integration_batch_if_needed(
                task_a_id,
                &patch_id,
                &["src.txt".to_string()],
            )
            .unwrap();
        assert_eq!(batch["status"].as_str(), Some("created"));
        assert_eq!(
            batch["integrator"]["integrator_model"].as_str(),
            Some("gpt-5.5")
        );
        let batch_id = batch["batch_id"].as_str().unwrap();
        let items = kernel
            .query_json(
                "SELECT task_id, patch_id, status
                 FROM integration_batch_items
                 WHERE batch_id=?1
                 ORDER BY task_id ASC",
                &[&batch_id],
            )
            .unwrap();
        assert_eq!(items.len(), 2);
        assert!(items.iter().any(|item| {
            item["task_id"].as_str() == Some(task_a_id)
                && item["patch_id"].as_str() == Some(patch_id.as_str())
                && item["status"].as_str() == Some("queued_for_integrator")
        }));
        assert!(items.iter().any(|item| {
            item["task_id"].as_str() == Some(task_b_id)
                && item["patch_id"].as_str() == Some("")
                && item["status"].as_str() == Some("pending_submission")
        }));
    }

    #[test]
    fn concurrent_submit_defers_root_and_queues_later_patch_for_integrator() {
        let repo = init_git_repo("concurrent_submit_route");
        fs::write(repo.join("b.txt"), "base b\n").unwrap();
        run(&repo, "git", &["add", "b.txt"]);
        run(
            &repo,
            "git",
            &[
                "-c",
                "user.email=test@example.com",
                "-c",
                "user.name=Test",
                "commit",
                "-m",
                "add b",
            ],
        );
        let kernel = CoordinationKernel::init(&repo, None).unwrap();
        enable_agent_worktrees(&kernel);
        kernel
            .update_repo_policy(&json!({"integrator_enabled": true}))
            .unwrap();

        let session_a = kernel
            .create_session_for_slot_key(
                "route-a", "Agent A", "codex", None, None, None, true, None, None,
            )
            .unwrap();
        let agent_a_id = session_a["agentId"].as_str().unwrap();
        let session_a_id = session_a["id"].as_str().unwrap();
        let worktree_a_id = session_a["worktreeId"].as_str().unwrap();
        let write_root_a = PathBuf::from(session_a["writeRoot"].as_str().unwrap());
        let task_a = kernel
            .create_task("Task A", Some("change src"), 0, 1, None, None, None, None)
            .unwrap();
        let task_a_id = task_a["id"].as_str().unwrap();
        kernel
            .claim_task(task_a_id, agent_a_id, session_a_id)
            .unwrap();
        kernel
            .acquire_lease(
                task_a_id,
                agent_a_id,
                session_a_id,
                "file:src.txt",
                "write",
                Some(600),
                None,
            )
            .unwrap();

        let session_b = kernel
            .create_session_for_slot_key(
                "route-b", "Agent B", "codex", None, None, None, true, None, None,
            )
            .unwrap();
        let agent_b_id = session_b["agentId"].as_str().unwrap();
        let session_b_id = session_b["id"].as_str().unwrap();
        let worktree_b_id = session_b["worktreeId"].as_str().unwrap();
        let write_root_b = PathBuf::from(session_b["writeRoot"].as_str().unwrap());
        let task_b = kernel
            .create_task("Task B", Some("change b"), 0, 1, None, None, None, None)
            .unwrap();
        let task_b_id = task_b["id"].as_str().unwrap();
        kernel
            .claim_task(task_b_id, agent_b_id, session_b_id)
            .unwrap();
        kernel
            .acquire_lease(
                task_b_id,
                agent_b_id,
                session_b_id,
                "file:b.txt",
                "write",
                Some(600),
                None,
            )
            .unwrap();

        fs::write(write_root_a.join("src.txt"), "changed by a\n").unwrap();
        fs::write(write_root_b.join("b.txt"), "changed by b\n").unwrap();

        let first = kernel
            .submit_patch(
                task_a_id,
                agent_a_id,
                session_a_id,
                Some(worktree_a_id),
                Some("a done"),
            )
            .unwrap();
        assert_eq!(first["ok"].as_bool(), Some(true));
        assert_eq!(
            first["data"]["concurrent_integration"]["auto_apply"]["mode"].as_str(),
            Some("integration_only")
        );
        assert_eq!(
            first["data"]["auto_merge"]["apply"]["data"]["root_fast_forward"]["status"].as_str(),
            Some("deferred_concurrent_integration_batch")
        );
        assert_eq!(
            fs::read_to_string(repo.join("src.txt")).unwrap(),
            "initial\n"
        );

        let second = kernel
            .submit_patch(
                task_b_id,
                agent_b_id,
                session_b_id,
                Some(worktree_b_id),
                Some("b done"),
            )
            .unwrap();
        assert_eq!(second["ok"].as_bool(), Some(true));
        assert_eq!(
            second["data"]["auto_merge"]["status"].as_str(),
            Some("queued_for_integrator")
        );
        assert_eq!(
            second["data"]["auto_merge"]["integrator"]["status"].as_str(),
            Some("initialized")
        );
        let batches = kernel
            .query_json(
                "SELECT * FROM integration_batches WHERE strategy='concurrent_integrator'",
                &[],
            )
            .unwrap();
        assert_eq!(batches.len(), 1);
        assert_eq!(batches[0]["status"].as_str(), Some("integrator_reviewing"));
        assert!(batches[0]["resolver_task_id"]
            .as_str()
            .is_some_and(|value| !value.is_empty()));
    }

    #[test]
    fn slot_busy_rejects_different_fresh_pty() {
        let repo = init_git_repo("slot_busy");
        let kernel = CoordinationKernel::init(&repo, None).unwrap();
        let first = kernel
            .create_session_for_slot_key(
                "codex-01",
                "Codex",
                "codex",
                None,
                None,
                Some("workspace-terminal-test-0-codex"),
                true,
                None,
                None,
            )
            .unwrap();
        let second = kernel.create_session_for_slot_key(
            "codex-01",
            "Codex",
            "codex",
            None,
            None,
            Some("workspace-terminal-test-1-codex"),
            true,
            None,
            None,
        );

        assert!(second.unwrap_err().contains("slot_busy"));
        let busy_events = kernel
            .query_json(
                "SELECT * FROM events WHERE event_type='agent_slot_busy'",
                &[],
            )
            .unwrap();
        assert_eq!(busy_events.len(), 1);
        let active = kernel
            .query_json(
                "SELECT * FROM agent_sessions WHERE agent_slot_id=?1 AND status='active'",
                &[&first["agentSlotId"].as_str().unwrap()],
            )
            .unwrap();
        assert_eq!(active.len(), 1);
    }

    #[test]
    fn terminal_contexts_use_unique_slot_scoped_agent_ids() {
        let repo = init_git_repo("terminal_context_agent_ids");
        let kernel = CoordinationKernel::init(&repo, None).unwrap();
        let first = kernel
            .prepare_terminal_context(
                "Codex",
                "codex",
                Some("workspace-terminal-test-0-codex"),
                Some("workspace-test"),
                None,
                None,
                None,
                None,
            )
            .unwrap();
        let second = kernel
            .prepare_terminal_context(
                "Codex",
                "codex",
                Some("workspace-terminal-test-1-codex"),
                Some("workspace-test"),
                None,
                None,
                None,
                None,
            )
            .unwrap();

        assert_ne!(first.agent_id, second.agent_id);
        assert_eq!(first.slot_key.as_deref(), Some("codex-01"));
        assert_eq!(second.slot_key.as_deref(), Some("codex-02"));
        let first_codex_home = first.codex_home_path.as_deref().unwrap_or_default();
        let second_codex_home = second.codex_home_path.as_deref().unwrap_or_default();
        assert!(!first_codex_home.is_empty());
        assert!(!second_codex_home.is_empty());
        assert_ne!(first_codex_home, second_codex_home);
        assert!(first_codex_home.contains("codex-home"));
        assert!(PathBuf::from(first_codex_home).join("config.toml").exists());
        assert!(PathBuf::from(first_codex_home)
            .join(format!(
                "{}.config.toml",
                first.codex_profile.as_deref().unwrap_or_default()
            ))
            .exists());
        assert!(first
            .env_vars()
            .contains(&("CODEX_HOME".to_string(), first_codex_home.to_string())));
    }

