        let second_id = second["id"].as_str().unwrap();

        kernel
            .add_task_dependency(first_id, second_id, Some("requires"))
            .unwrap();
        let reused = kernel
            .add_task_dependency(first_id, second_id, Some("requires"))
            .unwrap();
        assert_eq!(reused["reused"].as_bool(), Some(true));
