    #[test]
    fn patch_without_lease_resolves_after_late_lease_revalidation() {
        let repo = init_git_repo("patch_late_lease_revalidation");
        let kernel = CoordinationKernel::init(&repo, None).unwrap();
        enable_agent_worktrees(&kernel);
        let agent = kernel.create_or_get_agent("Codex", "codex", None).unwrap();
        let agent_id = agent["id"].as_str().unwrap();
        let task = kernel
            .create_task("Task", None, 0, 1, None, None, None, None)
            .unwrap();
        let task_id = task["id"].as_str().unwrap();
        let session = kernel
            .create_session(agent_id, None, None, true, None, None)
            .unwrap();
        let session_id = session["id"].as_str().unwrap();
        let worktree_id = session["worktreeId"]
            .as_str()
            .unwrap_or_else(|| panic!("missing worktreeId in session: {session}"));
        let write_root = PathBuf::from(session["writeRoot"].as_str().unwrap());
        kernel.claim_task(task_id, agent_id, session_id).unwrap();

        fs::write(write_root.join("src.txt"), "changed before lease\n").unwrap();
        kernel.scan_workspace_changes().unwrap();
        let failed = kernel
            .validate_patch(
                task_id,
                agent_id,
                session_id,
                Some(worktree_id),
                Some("no lease yet"),
            )
            .unwrap();
        assert_eq!(failed["ok"].as_bool(), Some(false));
        let open_before = kernel
            .query_json(
                "SELECT * FROM workspace_violations
                 WHERE task_id=?1
                   AND session_id=?2
                   AND status='open'
                   AND violation_kind IN ('patch_without_lease', 'unleased_write')",
                &[&task_id, &session_id],
            )
            .unwrap();
        assert_eq!(open_before.len(), 2);

        kernel
            .acquire_lease(
                task_id,
                agent_id,
                session_id,
                "file:src.txt",
                "write",
                Some(600),
                Some("Recover after missed pre-edit lease"),
            )
            .unwrap();
        let passed = kernel
            .validate_patch(
                task_id,
                agent_id,
                session_id,
                Some(worktree_id),
                Some("lease acquired"),
            )
            .unwrap();
        assert_eq!(passed["ok"].as_bool(), Some(true));
        assert_eq!(passed["data"]["validation_status"].as_str(), Some("passed"));
        let open_after = kernel
            .query_json(
                "SELECT * FROM workspace_violations
                 WHERE task_id=?1
                   AND session_id=?2
                   AND status='open'
                   AND violation_kind IN ('patch_without_lease', 'unleased_write')",
                &[&task_id, &session_id],
            )
            .unwrap();
        assert!(open_after.is_empty());
        let resolved = kernel
            .query_json(
                "SELECT * FROM workspace_violations
                 WHERE task_id=?1
                   AND session_id=?2
                   AND status='resolved'
                   AND json_extract(details_json, '$.resolution_reason')='superseded_by_current_lease_validation'",
                &[&task_id, &session_id],
            )
            .unwrap();
        assert_eq!(resolved.len(), 2);
    }

    #[test]
    fn shutdown_git_skip_worktree_violation_auto_resolves_after_revalidation() {
        let repo = init_git_repo("shutdown_git_skip_worktree_violation");
        let kernel = CoordinationKernel::init(&repo, None).unwrap();
        enable_agent_worktrees(&kernel);
        let agent = kernel.create_or_get_agent("Codex", "codex", None).unwrap();
        let agent_id = agent["id"].as_str().unwrap();
        let task = kernel
            .create_task("Task", None, 0, 1, None, None, None, None)
            .unwrap();
        let task_id = task["id"].as_str().unwrap();
        let session = kernel
            .create_session(agent_id, None, None, true, None, None)
            .unwrap();
        let session_id = session["id"].as_str().unwrap();
        let worktree_id = session["worktreeId"]
            .as_str()
            .unwrap_or_else(|| panic!("missing worktreeId in session: {session}"));
        let write_root = PathBuf::from(session["writeRoot"].as_str().unwrap());
        let worktree = kernel
            .query_one(
                "SELECT * FROM worktrees WHERE id=?1",
                &[&worktree_id],
                "missing worktree",
            )
            .unwrap();
        let branch_name = worktree["branch_name"].as_str().unwrap();

        kernel.claim_task(task_id, agent_id, session_id).unwrap();
        kernel
            .acquire_lease(
                task_id,
                agent_id,
                session_id,
                "file:src.txt",
                "write",
                Some(600),
                None,
            )
            .unwrap();
        fs::write(write_root.join("src.txt"), "changed\n").unwrap();
        let violation_id = kernel
            .create_workspace_violation(
                Some(task_id),
                Some(agent_id),
                Some(session_id),
                Some(worktree_id),
                "invalid_worktree_isolation",
                Some(write_root.to_string_lossy().as_ref()),
                None,
                "error",
                json!({
                    "reason": "invalid_git_worktree",
                    "details": {
                        "error": "git skipped because Diff Forge is shutting down (closing_terminals)",
                        "expected_branch": branch_name,
                        "path": write_root.to_string_lossy(),
                        "reason": "invalid_git_worktree",
                        "session_id": session_id,
                        "worktree_id": worktree_id,
                    },
                    "recovery_action": "session_interrupted",
                }),
            )
            .unwrap();

        let response = kernel
            .submit_patch(
                task_id,
                agent_id,
                session_id,
                Some(worktree_id),
                Some("leased"),
            )
            .unwrap();
        assert_eq!(
            response["ok"].as_bool(),
            Some(true),
            "unexpected submit response: {response}"
        );
        assert_eq!(
            response["data"]["validation_status"].as_str(),
            Some("passed")
        );
        let violation = kernel
            .query_one(
                "SELECT * FROM workspace_violations WHERE id=?1",
                &[&violation_id],
                "missing violation",
            )
            .unwrap();
        assert_eq!(violation["status"].as_str(), Some("resolved"));
        assert_eq!(
            violation["details_json"]["resolution_reason"].as_str(),
            Some("recovered_after_shutdown_git_skip")
        );
    }

